"""내장 도구 — Provider에 따라 자동 등록되는 도구들."""

from __future__ import annotations

import logging
from typing import Any

from mantis.tools.decorator import tool, ToolSpec
from mantis.tools.registry import ToolRegistry

logger = logging.getLogger(__name__)


def make_builtin_tools(
    registry: ToolRegistry,
    search: Any | None = None,
    sandbox: Any | None = None,
    workflows: Any | None = None,
) -> list[ToolSpec]:
    """Provider 구성에 따라 내장 도구를 생성."""
    specs: list[ToolSpec] = []

    # search_tools, list_tools — 항상 등록
    from mantis.tools.meta import make_registry_tools
    specs.extend(make_registry_tools(registry, graph_manager=search))

    # sandbox → execute_code, create_tool
    if sandbox is not None:
        try:
            from mantis.sandbox.tools import make_sandbox_tools
            specs.extend(make_sandbox_tools(sandbox))
        except ImportError:
            logger.warning("sandbox.tools를 import할 수 없음")

    # workflows → create_workflow, run_workflow, list_workflows
    if workflows is not None:
        try:
            from mantis.workflow.tools import make_workflow_tools
            specs.extend(make_workflow_tools(workflows, registry))
        except ImportError:
            logger.warning("workflow를 import할 수 없음")

    return specs
